  phrases: [{ nl: "Waar is de uitgang?", fr: "Où est la sortie ?", ipa: "/ʋaːr ɪs də ˈœyt.ɣɑŋ/" }, { nl: "Is het open?", fr: "Est-ce ouvert ?", ipa: "/ɪs ət ˈoː.pə/" }, { nl: "Het is gesloten.", fr: "C’est fermé.", ipa: "/ɦət ɪs ɣəˈsloː.tə/" }, { nl: "Dat is verboden.", fr: "C’est interdit.", ipa: "/dɑt ɪs vərˈboː.də/" }, { nl: "Moet ik duwen of trekken?", fr: "Dois-je pousser ou tirer ?", ipa: "/mut ɪk ˈdy.ʋə ɔf ˈtrɛ.kə/" }, { nl: "Waar is de wachtrij?", fr: "Où est la file d’attente ?", ipa: "/ʋaːr ɪs də ˈʋɑxt.rɛi/" }],
